INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '906747b8-b048-4117-825b-7a43fd112a3c',
  '00000000-0000-0000-0000-000000000001',
  $escape$nmap - Crafting a Comprehensive Pentesting Strategy$escape$,
  $escape$Reconnaissance with nmap's -sL and -n options provides an initial overview of target hosts. Subsequent scans with -sS and -sN reveal open TCP and UDP ports, respectively. Advanced scanning techniques, such as -sC for default scripts and -sV for version detection, expose vulnerabilities. Exploitation involves using tools like Metasploit with nmap's -script option to automate attacks. Post-exploitation includes maintaining a session with ncat or nc for further access. Comprehensive reporting is ensured with nmap's XML output format.$escape$,
  NULL,
  NULL,
