INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '8ed6f7d9-5d4c-4249-a79f-9d3025272aeb',
  '00000000-0000-0000-0000-000000000001',
  $escape$nmap - Legit Targets Only: Understanding Scope of Engagement and Authorization Requirements$escape$,
  $escape$When using nmap for penetration testing, it's essential to define the scope of engagement and adhere to authorization requirements. Start by specifying the target IP range with the -sn option to identify live hosts. Use the -n option to disable DNS resolution and the -P0 option to assume all hosts are up.
To ensure you're only scanning legitimate targets, use the -sV option to identify services and the -O option to detect operating systems. You can also use the --script option to run specific scripts, such as nmap-os- detection.nse, to gather more information.
Remember to always obtain proper authorization before scanning targets, especially if you're scanning private networks or sensitive systems.$escape$,
  NULL,
  NULL,
