INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '7f2abd3e-3cd9-42bf-83e6-e02d51d3dbb9',
  '00000000-0000-0000-0000-000000000001',
  $escape$Nmap — Leveraging OS Fingerprinting for Accurate Scans$escape$,
  $escape$To accurately identify hosts and services, use OS fingerprinting with the `-O` flag. This enables nmap to perform TCP SYN and ACK scans to gather fingerprint data. For example, to fingerprint a host and list the potential operating systems, use `nmap -O -sS -sA 192.168.1.100`. You can also use the `--max-os-diff` option to filter results based on the maximum allowed OS difference. Additionally, nmap's NSE scripts can be used to gather more information about the host, such as open ports and services. Use the `--script` option to specify the scripts to run, like `nmap --script http-headers,http-methods 192.168.1.100`. To speed up scans, use the `-T` option to adjust the timing template.$escape$,
  $escape$nmap -O -sS -sA 192.168.1.100$escape$,
  $escape$bash$escape$,
