INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'f701feaf-2782-40b5-9492-c0a7d0721b91',
  '00000000-0000-0000-0000-000000000001',
  $escape$nmap — Decoding Network Traffic with Wireshark$escape$,
  $escape$When analyzing network traffic with nmap, Wireshark's packet capture and display filter capabilities can significantly enhance your understanding of network behavior. You can use nmap's -w flag to capture traffic and save it as a PCAP file, which can then be loaded into Wireshark for analysis. Display filters allow you to narrow down the captured traffic to specific protocols, ports, or hosts. For example, to capture HTTP traffic from a specific host, use the -w flag followed by the display filter 'http.host == <host_IP>'. Protocol dissection in Wireshark enables you to inspect packet contents and identify potential security vulnerabilities.$escape$,
  $escape$nmap -w capture.pcap -p 80 --host <host_IP>$escape$,
  $escape$bash$escape$,
