INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '0354a9ef-6f11-4c3b-9b10-b7c7c75f09f4',
  '00000000-0000-0000-0000-000000000001',
  $escape$nmap - Leveraging CVE Research and Exploit Databases for Targeted Exploitation$escape$,
  $escape$nmap provides a rich interface for searching and exploiting known vulnerabilities. Utilize the --script option to execute NSE scripts that target specific CVEs. For instance, `nmap -sV --script=cve-2021-41820-host` will search for hosts vulnerable to CVE-2021-41820. To integrate exploit databases like Exploit-DB, leverage the --script-args option, which allows you to pass arguments to NSE scripts. For example, `nmap -sV --script=cve-2021-41820-host --script-args exploitdb_url=https://www.exploit-db.com/` will fetch exploit code from Exploit-DB for the identified CVE.$escape$,
  $escape$nmap -sV --script=cve-2021-41820-host --script-args exploitdb_url=https://www.exploit-db.com/$escape$,
  $escape$bash$escape$,
