INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  'd02a7247-6a67-41bd-b836-6b23e4e438b7',
  '00000000-0000-0000-0000-000000000001',
  $escape$nmap - Leveraging Metasploit's Meterpreter with NSE Scripts$escape$,
  $escape$When combining nmap with Metasploit, you can utilize the Meterpreter payload to execute arbitrary commands on compromised hosts. In nmap, this is achieved through the `msfvenom` NSE script, which generates Meterpreter payloads in various formats. To use it, simply add the script to your nmap command: `nmap -script msfvenom <target>`. The generated payload can then be executed on the compromised host using Meterpreter's `execute` command. Additionally, you can use nmap's `auxiliary` modules to interact with Metasploit's framework, enabling more sophisticated attacks.$escape$,
  NULL,
  NULL,
