INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '12efa62c-ebba-480f-abb6-8a086c0092f2',
  '00000000-0000-0000-0000-000000000001',
  $escape$nmap - Mapping Attack Surface with OSINT and Passive Recon$escape$,
  $escape$Effective reconnaissance begins with identifying potential entry points. Use `nmap -sV` to scan for open ports and services, then apply OSINT techniques to gather information about the target's network topology. For passive recon, leverage `nmap --script=masscan` to gather IP addresses without sending probes. To visualize your attack surface, utilize `nmap -oG` to generate a Grepable output, then use tools like `nmap-services` to map services to ports.$escape$,
  $escape$nmap -sV -oG - --script=masscan -p 1-65535 192.168.1.1$escape$,
  $escape$bash$escape$,
