INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '6c04eb46-1a8d-4ccc-bf5d-7e85f4c7ccef',
  '00000000-0000-0000-0000-000000000001',
  $escape$nmap - Red Teaming vs Pentesting: When Stealth Matters$escape$,
  $escape$Red Teaming and Pentesting both involve simulating cyberattacks, but the scope, persistence, and stealth differ. Red Team exercises focus on realistic, long-term engagements that test an organization's defenses, often using nmap's -sC and -sV scripts for comprehensive vulnerability assessment. In contrast, Pentesting is typically shorter-term, focusing on identifying vulnerabilities and exploiting them before the system is patched. nmap's -O and -sV options can help distinguish between these two approaches. For instance, Red Team exercises might use nmap to maintain persistence by identifying open ports and exploiting them to maintain access.$escape$,
  $escape$nmap -sC -sV -O target$escape$,
  $escape$bash$escape$,
