INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '097efd8a-41af-473e-ba2a-3ad11690b1fe',
  '00000000-0000-0000-0000-000000000001',
  $escape$nmap - Mastering CTF Challenges with NSE Scripts$escape$,
  $escape$When participating in Capture The Flag (CTF) challenges, mastering nmap's NSE (Nmap Scripting Engine) scripts is crucial. Familiarize yourself with categories like 'vuln' (vulnerability detection), 'brute' (password cracking), and 'safe' (safety checks). Utilize the 'nmap -script' option to execute specific script categories. For instance, to identify potential vulnerabilities, run `nmap -script vuln <target_IP>`. To automate brute-force attacks, use the 'nmap -script brute' option. Be cautious when executing 'nmap -script safe' to prevent unnecessary resource consumption.$escape$,
  $escape$nmap -script vuln -script-args 'unsafe=1' <target_IP>$escape$,
  $escape$bash$escape$,
